/**
 * Mock data for the Operations Overview page.
 * Shape loosely matches what a real API would return.
 */

export type AIAccent = "ops" | "finance" | "growth" | "customers" | "amber";

export type AICardBridgePage =
  | "reorder"
  | "update-costs"
  | "liquidate"
  | "replenishment-plan"
  | "rebalance"
  | "approve-po"
  | "escalate-po"
  | "receive"
  | "capture-receipt"
  | "produce"
  | "return"
  | "packaging-review";

export type AICard = {
  tag: string;
  title: string;
  body: string;
  accent: AIAccent;
  /** Optional Bridge page the "Bridge →" button on this card should open. */
  bridgePage?: AICardBridgePage;
};

export type StockState = "out" | "critical" | "low" | "healthy";

export type StockSeg = {
  state: StockState;
  count: number;
  pct: number;
  label: string;
};

export type Shipment = {
  po: string;
  supplier: string;
  item: string;
  value: number;
  day: number; // offset from today; negative = overdue
  status: "ontrack" | "partial" | "late";
  received: number;
  ordered: number;
  when: string;
};

export type CategoryRow = {
  name: string;
  count: number;
  value: string;
  delta: string;
  deltaState: "up" | "down" | "flat";
};

export type VelocityRow = {
  rank: number;
  name: string;
  rate: string;
};

export type ChangedItem = {
  kind: "received" | "sold" | "added" | "cost" | "config";
  title: string;
  time: string;
};

export type DhtBar = {
  day: string;
  value: number;
  isToday?: boolean;
};

export type RfBar = {
  label: string;
  num: string;
  fillPct: number;
  color: "green" | "amber" | "red" | "purple";
};

export type RfCard = {
  head: string;
  headTooltip?: { label: string; body: string };
  value: string;
  valueState: "pos" | "neg" | "neutral";
  sub: string;
  subAlert?: boolean;
  bars: RfBar[];
};

